static_checks.command:
python3 - <<'PY'
import csv, pathlib, shlex
root = pathlib.Path('.')
missing = []
for row in csv.DictReader((root / 'references/use-case-registry.csv').open(newline='')):
    for key in ('detail_files', 'artifact_templates'):
        for value in filter(None, [p.strip() for p in (row.get(key) or '').split(';')]):
            if not (root / value).exists():
                missing.append((row['use_case'], value))
    script = (row.get('script') or '').strip()
    if script:
        script_path = shlex.split(script)[0]
        if not (root / script_path).exists():
            missing.append((row['use_case'], script_path))
if missing:
    raise SystemExit(f'missing registry targets: {missing}')
print('registry targets resolved')
PY
